%data_opto=[9 2 4 1 7 8;
%    9 1 4 0 2 4;
%    5 7 8 7 7 8;
%    3 4 2 5 1 2]; %Matrix where each row represents the average per cell
data_sound_fac=data_sound(data_response==1,:);
data_sound_sup=data_sound(data_response==2,:);
data_sound_NR=data_sound(data_response==0,:);

for ii=1:size(data_sound_fac,1)
    data_sound_fac(ii,:)= data_sound_fac(ii,:)-nanmean(data_sound_fac(ii,500:750));
end

for ii=1:size(data_sound_sup,1)
    data_sound_sup(ii,:)= data_sound_sup(ii,:)-nanmean(data_sound_sup(ii,500:750));
end
for ii=1:size(data_sound_NR,1)
    data_sound_NR(ii,:)= data_sound_NR(ii,:)-nanmean(data_sound_NR(ii,500:750));
end

data_sound_fac_avg = nanmean(data_sound_fac); %Calculate population average
data_sound_fac_sd = nanstd(data_sound_fac); %Calculate population SD
data_sound_fac_sem = nanstd(data_sound_fac)/sqrt(size(data_sound_fac,1)); %Calculate population SEM

data_sound_sup_avg = nanmean(data_sound_sup); %Calculate population average
data_sound_sup_sd = nanstd(data_sound_sup); %Calculate population SD
data_sound_sup_sem = nanstd(data_sound_sup)/sqrt(size(data_sound_sup,1)); %Calculate population SEM

data_sound_NR_avg = nanmean(data_sound_NR); %Calculate population average
data_sound_NR_sd = nanstd(data_sound_NR); %Calculate population SD
data_sound_NR_sem = nanstd(data_sound_NR)/sqrt(size(data_sound_NR,1)); %Calculate population SEM

%data_opto_avg = nanmean(data_opto); %Calculate population average
%data_opto_sd = nanstd(data_opto); %Calculate population SD
%data_opto_sem = nanstd(data_opto)/sqrt(size(data_opto,1)); %Calculate population SEM

%Plot the averages with sem (or sd, then change sem to sd). Color black 'k'
%for sound and blue 'b' for opto. The x-axis runs from -0.25s to 1s. Modify
%to match the data
figure; hold on; 
shadedErrorBar(linspace(-0.75,1.25,size(data_sound_fac_avg,2)),data_sound_fac_avg,data_sound_fac_sem,'r');
shadedErrorBar(linspace(-0.75,1.25,size(data_sound_sup_avg,2)),data_sound_sup_avg,data_sound_sup_sem,'b');
shadedErrorBar(linspace(-0.75,1.25,size(data_sound_NR_avg,2)),data_sound_NR_avg,data_sound_NR_sem,'k');

%Draw vertical lines to indicate the start and end of the stimulus (20 ms
%for sound).
    line([0 0],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'g','LineWidth',0.5);
    line([0.06 0.06],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'g','LineWidth',0.5);
   xlim([-0.5 1]); %Define the xlimits
ylim([-10 30])
set(gca,'fontSize',15,'FontName','Arial');
ylabel('Spike rate (Hz)')
xlabel('Time (s)')


%% Calculate latency facilitation cells
threshold = 0.1; % 10% of max
% Facilitation cells
latency=[];
for ii=1:size(data_sound_fac,1)
    idx = data_sound_fac(ii,:);
    [idx_peak idx_peakloc] = nanmax(idx(750:1250));
    idx_threshold=idx(750:1250)>=(threshold*idx_peak);
    idx_threshold(idx_peakloc+1:end)=[];
    idx_threshold=idx_threshold+1;
    idx_logical = find(idx_threshold==1);
    try
    latency(ii,1) = idx_logical(end);
    catch
       latency(ii,1) = 0;
    end
    latency(ii,2) = latency(ii,1)/1000;

    figure; hold on;
    plot(linspace(-0.75,1.25,size(data_sound_fac_avg,2)),idx,'k');
   line([latency(ii,2) latency(ii,2)],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'r','LineWidth',0.5);
ii
pause;
close all; 
end

for ii=[19 24 35]
    idx = data_sound_fac(ii,:);
    [idx_peak idx_peakloc] = nanmax(idx(750:1250));
    idx_threshold=idx(750:1250)>=(threshold*idx_peak);
    idx_threshold(idx_peakloc+1:end)=[];
%     idx_threshold=idx_threshold+1;
    idx_logical = find(idx_threshold>0,1,'first');
%     try
    latency(ii,1) = idx_logical(1);
%     catch
%        latency(ii,1) = 0;
%     end
    latency(ii,2) = latency(ii,1)/1000;

    figure; hold on;
    plot(linspace(-0.75,1.25,size(data_sound_fac_avg,2)),idx,'k');
   line([latency(ii,2) latency(ii,2)],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'r','LineWidth',0.5);
ii
pause;
close all; 
end

%exclude 
latency([18 22 25],:)=NaN;

%% Calculate latency suppression cells
threshold = 0.1; % 10% of max
latency=[];
% Suppression cells

for ii=1:size(data_sound_sup,1)
    idx = data_sound_sup(ii,:);
    [idx_peak idx_peakloc] = nanmin(idx(750:1250));
    idx_threshold=idx(750:1250)<=(threshold*idx_peak);
    idx_threshold(idx_peakloc+1:end)=[];
    idx_threshold=idx_threshold+1;
    idx_logical = find(idx_threshold==1);
    try
    latency(ii,1) = idx_logical(end);
    catch
       latency(ii,1) = 0;
    end
    latency(ii,2) = latency(ii,1)/1000;

    figure; hold on;
    plot(linspace(-0.75,1.25,size(data_sound_fac_avg,2)),idx,'k');
   line([latency(ii,2) latency(ii,2)],   [min(get(gca, 'Ylim')) max(get(gca, 'Ylim'))], 'Color', 'r','LineWidth',0.5);
ii
pause;
close all; 
end

